const cellKey = ([x, y]: Cell): string => `${x},${y}`;

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set<string>(cells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const key = cellKey(neighbor);
        const existing = neighborCounts.get(key);
        if (existing) {
          existing.count++;
        } else {
          neighborCounts.set(key, { cell: neighbor, count: 1 });
        }
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
    if (count === 3 || (count === 2 && liveSet.has(key))) {
      result.push(cell);
    }
  }

  return result;
}

