type Cell = [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const shouldBeAlive = (neighborCount: number, wasAlive: boolean): boolean =>
  neighborCount === 3 || (neighborCount === 2 && wasAlive);

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set<string>(cells.map(cellKey));
  const candidates = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const key = cellKey(neighbor);
        const entry = candidates.get(key);
        if (entry) entry.count++;
        else candidates.set(key, { cell: neighbor, count: 1 });
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, { cell, count }] of candidates) {
    if (shouldBeAlive(count, liveSet.has(key))) result.push(cell);
  }

  return result;
}

